#!/usr/bin/env python3
"""Debug script to understand AST structure of try blocks."""

import ast

code_with_try = """
while True:
    try:
        some_function_that_raises()
    except Exception:
        print('Shut down')
        sys.exit()
"""

code_without_try = """
while True:
    print("hello")
    break
"""

def dump_ast(code, name):
    print(f"\n=== {name} ===")
    tree = ast.parse(code)
    print(ast.dump(tree, indent=2))

if __name__ == "__main__":
    dump_ast(code_with_try, "Code with try block")
    dump_ast(code_without_try, "Code without try block")

