#!/usr/bin/env python3
"""Comprehensive test for the InfiniteWhileLoopViolation fix."""

import ast
from wemake_python_styleguide.violations.best_practices import InfiniteWhileLoopViolation
from wemake_python_styleguide.visitors.ast.loops import WrongLoopVisitor
from wemake_python_styleguide.options.config import Configuration

test_cases = [
    # Should NOT trigger violation (according to issue)
    ("""
while True:
    try:
        some_function_that_raises()
    except Exception:
        print('Shut down')
        sys.exit()
""", False, "Try/except with sys.exit"),

    # Should NOT trigger violation (any try block is acceptable per issue)
    ("""
while True:
    try:
        some_function_that_raises()
    except Exception:
        print('Error occurred')
""", False, "Try/except without exit"),

    # Should NOT trigger violation (nested try)
    ("""
while True:
    if condition:
        try:
            do_something()
        except:
            pass
""", False, "Nested try block"),

    # Should trigger violation (no try, no break/raise/return)
    ("""
while True:
    print("hello")
""", True, "Simple infinite loop without exit"),

    # Should NOT trigger violation (has break)
    ("""
while True:
    break
""", False, "Loop with break"),

    # Should NOT trigger violation (has raise)
    ("""
while True:
    raise ValueError()
""", False, "Loop with raise"),

    # Should NOT trigger violation (has return)
    ("""
def func():
    while True:
        return
""", False, "Loop with return"),

    # Edge case: try in condition (should still trigger violation)
    ("""
while True:
    if True:
        pass
""", True, "Loop without try"),
]

def test_case(code, should_have_violation, description):
    """Test a single case."""
    print(f"\n=== {description} ===")

    try:
        tree = ast.parse(code)
        visitor = WrongLoopVisitor(Configuration(), tree=tree)
        visitor.run()

        violations = visitor.violations
        infinite_loop_violations = [v for v in violations if isinstance(v, InfiniteWhileLoopViolation)]

        has_violation = len(infinite_loop_violations) > 0

        if should_have_violation and has_violation:
            print("✅ CORRECT: Violation found as expected")
        elif not should_have_violation and not has_violation:
            print("✅ CORRECT: No violation found as expected")
        elif should_have_violation and not has_violation:
            print("❌ ERROR: Expected violation but none found")
        else:  # not should_have_violation and has_violation
            print("❌ ERROR: Unexpected violation found")

    except Exception as e:
        print(f"❌ Error: {e}")

if __name__ == "__main__":
    for code, should_have_violation, description in test_cases:
        test_case(code, should_have_violation, description)
